    /**
     * The immediate parent — null at the campaign level (the tree root), the campaign id at ad_group level, the ad-group id at ad/keyword levels. Use it to attach this node to its parent when assembling the tree.
     */
    parent_id: string | null;
    /**
     * The serving status of this node (ENABLED / PAUSED / REMOVED — Google may also return the UNSPECIFIED/UNKNOWN sentinels).
     */
    status: 'UNSPECIFIED' | 'UNKNOWN' | 'ENABLED' | 'PAUSED' | 'REMOVED';
    /**
     * The advertising channel type — present on campaign nodes only (null at ad_group / ad / keyword).
     */
    type: 'UNSPECIFIED' | 'UNKNOWN' | 'SEARCH' | 'DISPLAY' | 'SHOPPING' | 'HOTEL' | 'VIDEO' | 'MULTI_CHANNEL' | 'LOCAL' | 'SMART' | 'PERFORMANCE_MAX' | 'LOCAL_SERVICES' | 'TRAVEL' | 'DEMAND_GEN' | null;
    /**
     * What kind of children this node has: ad_group, asset_group, or none. The per-type expand hint.
     */
    child_kind: 'ad_group' | 'asset_group' | 'none';
    /**
     * Whether the tree read can fetch this node’s children today (true only for ad-group channel types in this version).
     */
    expandable: boolean;
    /**
     * The campaign’s average daily budget in micros (1/1,000,000 of the account currency). Present on campaign nodes only — null at ad_group / ad / keyword (and null when a campaign has no budget).
     */
    budget_micros: number | null;
    /**
     * The requested metrics keyed by name; only the metrics you asked for are present. Google’s authoritative per-level numbers (no client roll-up).
     */
    metrics: {
        impressions?: number | null;
        clicks?: number | null;
        ctr?: number | null;
        average_cpc?: number | null;
        cost_micros?: number | null;
        conversions?: number | null;
        conversions_value?: number | null;
        cost_per_conversion?: number | null;
    };
    /**
     * Spend for this node in micros (1/1,000,000 of the account currency), as Google reports it.
     */
    cost_micros: number;
    /**
     * Spend for this node in the account currency (cost_micros / 1,000,000).
     */
