export type TokensMintData = {
    /**
     * Mint a short-lived, profile-scoped frontend token. Called by your backend with a secret `pr_` key; the returned token is safe to hand to a browser.
     */
    body: {
        /**
         * Which profiles the minted token may act on. Resolved dynamically per request, so an `external_id` selector also covers profiles created after the token was minted.
         */
        profile_scope: {
            type: 'profile_ids';
            values: Array<string>;
        } | {
            type: 'external_id';
            values: Array<string>;
        } | {
            type: 'all';
        };
        /**
         * What the token grants — coarse `resource:read` / `resource:write` per business area. At least one is required (a token with no scopes can do nothing). Money/structural writes are not a scope: those endpoints are server-side only and a browser token simply cannot reach them.
         */
        scopes: Array<'profiles:read' | 'profiles:write' | 'connections:read' | 'connections:write' | 'ads:read' | 'ads:write' | 'posts:read' | 'posts:write' | 'media:read' | 'media:write'>;
        /**
         * Token lifetime in seconds. Default 900 (15 min), max 1800 (30 min). Short TTL is the revocation model — there is no revocation store.
         */
        ttl_seconds?: number;
    };
    path?: never;
    query?: never;
    url: '/tokens';
};

